import{_ as t}from"./chunks/trackbar.LGCXX873.js";import{_ as a,o as r,c as e,ae as i}from"./chunks/framework.C00B0EYs.js";const p=JSON.parse('{"title":"轨道与音频","description":"管理轨道层、分配文件并控制轨道状态。","frontmatter":{"title":"轨道与音频","description":"管理轨道层、分配文件并控制轨道状态。"},"headers":[],"relativePath":"zh/docs/guide/tracks-and-audio.md","filePath":"zh/docs/guide/tracks-and-audio.md"}'),l={name:"zh/docs/guide/tracks-and-audio.md"};function n(s,o,d,c,u,_){return r(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="轨道与音频" tabindex="-1">轨道与音频 <a class="header-anchor" href="#轨道与音频" aria-label="Permalink to &quot;轨道与音频&quot;">​</a></h1><p>轨道是 Motor Sound Editor 项目的基础构件。每条轨道都可以拥有自己的音频文件、颜色、名称、曲线数据与可见性状态。通过合理组织多条轨道，你可以模拟从逆变器高频啸叫到电机低频轰鸣的复杂叠加效果。</p><p><img src="'+t+'" alt="轨道侧栏"></p><h2 id="_1-轨道基本概念" tabindex="-1">1. 轨道基本概念 <a class="header-anchor" href="#_1-轨道基本概念" aria-label="Permalink to &quot;1. 轨道基本概念&quot;">​</a></h2><p>在编辑器中，音频处理是基于“层”的。每一条轨道都代表一个独立的音源层，其最终输出由该轨道上的曲线数据实时驱动。</p><ul><li><strong>活动轨道（Active Track）</strong>：在侧栏点击任一轨道后，该轨道会高亮显示，主图表工作区也会切换到这条轨道的曲线。</li><li><strong>轨道组织</strong>：你可以按声音频段或功能组织轨道，例如高频层、中频层和基频层，以便于管理。</li></ul><h2 id="_2-轨道属性与状态" tabindex="-1">2. 轨道属性与状态 <a class="header-anchor" href="#_2-轨道属性与状态" aria-label="Permalink to &quot;2. 轨道属性与状态&quot;">​</a></h2><p>每条轨道都配备了一组常用控件，用于快速调整编辑与试听行为：</p><ul><li><strong>名称（Name）</strong>：可改成更容易识别的名称，例如 <code>Inverter_High</code> 或 <code>Cooling_Fan</code>。</li><li><strong>颜色（Color）</strong>：轨道颜色会同时反映在侧栏色条和主图表曲线中，便于区分。</li><li><strong>可见性（Show / Hide）</strong>：控制轨道是否在图表中显示。当前实现中，被隐藏的轨道也不会参与试听。</li><li><strong>静音（Mute）</strong>：禁用该轨道的音频输出，但保留其编辑数据。</li></ul><h2 id="_3-音频资源管理" tabindex="-1">3. 音频资源管理 <a class="header-anchor" href="#_3-音频资源管理" aria-label="Permalink to &quot;3. 音频资源管理&quot;">​</a></h2><p>音轨的核心是它所绑定的原始音频文件。Motor Sound Editor 采用非破坏性编辑，原始文件不会被修改。</p><ul><li><strong>文件分配</strong>：点击轨道上的文件选择图标或路径区域，即可从本地文件系统导入音频。</li><li><strong>支持格式</strong>：当前支持 <code>.wav</code> 和 <code>.ogg</code>。</li><li><strong>循环试听</strong>：编辑器会循环播放轨道绑定的音频片段，你只需要通过曲线控制它在不同速度下的表现。</li><li><strong>替换文件</strong>：替换音频后，新的文件会成为当前轨道的有效资源；旧文件在保存或另存为时会被未引用资源清理机制移除。</li></ul><h2 id="_4-曲线数据关联" tabindex="-1">4. 曲线数据关联 <a class="header-anchor" href="#_4-曲线数据关联" aria-label="Permalink to &quot;4. 曲线数据关联&quot;">​</a></h2><p>轨道与曲线数据是严格绑定且彼此隔离的：</p><ul><li><strong>数据分离</strong>：每条轨道都独立存储其牵引（Traction）与制动（Brake）模式下的 Pitch / Volume 曲线。</li><li><strong>独立编辑</strong>：在轨道 A 中编辑关键帧，不会影响轨道 B。</li></ul>',15)])])}const m=a(l,[["render",n]]);export{p as __pageData,m as default};
